// Zero-submission-day check (PRD NFR-Reliability): a silently broken form
// looks exactly like a quiet day, so alert on zero and let a human look.
const fs = require('fs');
let m = { days: {} };
try { m = JSON.parse(fs.readFileSync('/home/node/.n8n/wgc-metrics.json', 'utf8')); } catch (e) { /* no traffic ever */ }
const day = new Date().toISOString().slice(0, 10);
const d = m.days[day] || { submissions: 0, bots: 0 };
return [{ json: { day, submissions: d.submissions, bots: d.bots, quiet: d.submissions === 0 } }];

// Weekly conversion-log export (instrument I1): submissions, delivered-path
// split, bot rejects for the last 7 days. Counts only - never PII.
const fs = require('fs');
let m = { days: {} };
try { m = JSON.parse(fs.readFileSync('/home/node/.n8n/wgc-metrics.json', 'utf8')); } catch (e) { /* no data */ }
const lines = [];
const totals = { submissions: 0, bots: 0, delivered_api: 0, delivered_email: 0 };
for (let i = 7; i >= 1; i--) {
  const day = new Date(Date.now() - i * 86400000).toISOString().slice(0, 10);
  const d = m.days[day] || { submissions: 0, bots: 0, delivered_api: 0, delivered_email: 0 };
  lines.push(day + '  submissions=' + d.submissions + '  api=' + d.delivered_api + '  email=' + d.delivered_email + '  bots=' + d.bots);
  for (const k of Object.keys(totals)) totals[k] += d[k] || 0;
}
lines.push('');
lines.push('WEEK TOTAL  submissions=' + totals.submissions + '  api=' + totals.delivered_api + '  email=' + totals.delivered_email + '  bots=' + totals.bots);
return [{ json: { report: lines.join('\n') } }];
